  1→import React, { useState, useRef, useCallback } from 'react';
  2→import { Sparkles, TrendingUp, Target, Award, MousePointerClick, ArrowRight, ScanLine, Code2, Globe2, Fuel, Zap, Star, Check, Search, Bot, BrainCircuit, Database, Share2, Layers, Infinity, Radio, Globe, Droplet, Loader2, Gift, Shield, UserCheck, GraduationCap, BadgeCheck } from 'lucide-react';
  3→import { User } from '../types';
  4→import ScoreRing from '../components/ScoreRing';
  5→import { auditAnswerFirst, AnswerFirstAuditResult } from '../services/answer-first-audit';
  6→
  7→interface HomeProps {
  8→  onNavigate: (view: 'analyze' | 'login' | 'recharge' | 'directory') => void;
  9→  user: User | null;
 10→  onDirectRecharge?: (packId: number) => void;
 11→}
 12→
 13→const Home: React.FC<HomeProps> = ({ onNavigate, user, onDirectRecharge }) => {
 14→
 15→  // ── Score Gratuit State ──
 16→  const [brandName, setBrandName] = useState('');
 17→  const [siteUrl, setSiteUrl] = useState('');
 18→  const [isAnalyzing, setIsAnalyzing] = useState(false);
 19→  const [auditResult, setAuditResult] = useState<AnswerFirstAuditResult | null>(null);
 20→  const [auditError, setAuditError] = useState<string | null>(null);
 21→  const resultsRef = useRef<HTMLDivElement>(null);
 22→
 23→  // Derive E-E-A-T pillar scores from the 6 audit categories
 24→  const eeatPillars = auditResult ? [
 25→    { label: 'Experience', icon: <UserCheck size={16} />, score: Math.round((auditResult.categories.contentFreshness.score + auditResult.categories.answerFirst.score) / 2) },
 26→    { label: 'Expertise', icon: <GraduationCap size={16} />, score: Math.round((auditResult.categories.faqStructure.score + auditResult.categories.semanticHtml.score) / 2) },
 27→    { label: 'Authority', icon: <BadgeCheck size={16} />, score: Math.round((auditResult.categories.schemaOrg.score + auditResult.categories.metaOptimization.score) / 2) },
 28→    { label: 'Trust', icon: <Shield size={16} />, score: Math.round((auditResult.categories.metaOptimization.score + auditResult.categories.schemaOrg.score + auditResult.categories.answerFirst.score) / 3) },
 29→  ] : [];
 30→
 31→  const handleFreeAudit = useCallback(async () => {
 32→    if (!brandName.trim() || !siteUrl.trim()) {
 33→      setAuditError('Veuillez remplir les deux champs.');
 34→      return;
 35→    }
 36→    // Basic URL validation
 37→    let finalUrl = siteUrl.trim();
 38→    if (!/^https?:\/\//i.test(finalUrl)) {
 39→      finalUrl = 'https://' + finalUrl;
 40→    }
 41→    try {
 42→      new URL(finalUrl);
 43→    } catch {
 44→      setAuditError('URL invalide. Exemple : https://www.example.com');
 45→      return;
 46→    }
 47→
 48→    setAuditError(null);
 49→    setAuditResult(null);
 50→    setIsAnalyzing(true);
 51→
 52→    try {
 53→      const result = await auditAnswerFirst(finalUrl, brandName.trim());
 54→      setAuditResult(result);
 55→      // Scroll to results after a small delay for render
 56→      setTimeout(() => {
 57→        resultsRef.current?.scrollIntoView({ behavior: 'smooth', block: 'center' });
 58→      }, 150);
 59→    } catch (err) {
 60→      setAuditError('Une erreur est survenue lors de l\'analyse. Veuillez reessayer.');
 61→    } finally {
 62→      setIsAnalyzing(false);
 63→    }
 64→  }, [brandName, siteUrl]);
 65→
 66→  const getScoreLabel = (score: number): string => {
 67→    if (score >= 80) return 'Excellent';
 68→    if (score >= 60) return 'Bon';
 69→    if (score >= 40) return 'Moyen';
 70→    if (score >= 20) return 'Faible';
 71→    return 'Critique';
 72→  };
 73→
 74→  const getScoreColor = (score: number): string => {
 75→    if (score >= 80) return 'text-purple-400';
 76→    if (score >= 60) return 'text-violet-400';
 77→    if (score >= 40) return 'text-amber-400';
 78→    return 'text-red-400';
 79→  };
 80→
 81→  const getBarColor = (score: number): string => {
 82→    if (score >= 80) return 'bg-purple-500';
 83→    if (score >= 60) return 'bg-violet-500';
 84→    if (score >= 40) return 'bg-amber-500';
 85→    return 'bg-red-500';
 86→  };
 87→
 88→  const handleStartAnalysis = () => {
 89→    if (user) {
