145→
146→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.04] border border-white/[0.08] text-gray-400 text-xs font-medium tracking-wide uppercase mb-10">
147→          <Sparkles size={12} className="text-purple-400" />
148→          <span>Plateforme AEO / GEO</span>
149→        </div>
