171→      {/* ── SCORE GRATUIT DE VISIBILITE IA ── */}
172→      <div className="mb-32 relative" id="score-gratuit">
173→        {/* Ambient glow */}
174→        <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[600px] bg-purple-600/[0.06] blur-[180px] rounded-full -z-10 pointer-events-none"></div>
175→
